import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = Array.isArray(res.data) ? res.data : (res.data?.data || []);
      setHistory(data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  // 1. DYNAMIC THEME OVERRIDE (Forcing #000000)
  const theme = useMemo(() => ({
    bg: isDark ? '#000000' : '#ffffff',
    card: isDark ? '#000000' : '#ffffff',
    text: isDark ? '#ffffff' : '#000000',
    border: isDark ? '#1a1a1a' : '#e5e7eb',
    overlay: isDark ? 'rgba(0,0,0,0.98)' : 'rgba(255,255,255,0.9)',
  }), [isDark]);

  if (loading) return <div style={{...centerStyle, color: 'var(--accent-primary)'}}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={{...containerStyle, background: theme.bg, color: theme.text}}>
      {/* --- Header --- */}
      <div style={{...headerRow, borderBottom: `1px solid ${theme.border}`}}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={{ fontSize: '1.4rem', fontWeight: 900, margin: 0, color: theme.text }}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES</span>
      </div>

      {/* --- Card List --- */}
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} style={{...cardStyle, background: theme.card, border: `1px solid ${theme.border}`}}>
            <div style={{ flex: 1 }}>
              <div style={tagRow}>
                <span style={{ fontSize: '0.75rem', color: isDark ? '#888' : '#666', display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <Calendar size={12}/> {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={{ fontSize: '0.75rem', color: 'var(--accent-primary)', fontWeight: 800 }}>
                  <ShieldCheck size={12}/> RISK_SCORE: {item.risk_score}
                </span>
              </div>
              <h4 style={{ margin: 0, color: theme.text, fontSize: '1.1rem' }}>{item.goal}</h4>
            </div>

            <div style={{...actionColumn, borderLeft: `1px solid ${theme.border}`}}>
              <button onClick={() => setSelectedItem(item)} style={{...iconBtn, color: isDark ? '#fff' : '#444'}}><Eye size={20}/></button>
              <button onClick={() => handleDelete(item.id)} style={{...iconBtn, color: '#ef4444'}}><Trash2 size={20}/></button>
            </div>
          </div>
        ))}
      </div>

      {/* --- OLED BLACK MODAL --- */}
      {selectedItem && (
        <div style={{...modalOverlay, background: theme.overlay}}>
          <div style={{...modalContent, background: theme.bg, border: `2px solid var(--accent-primary)`}}>
            <div style={{...modalHeader, background: isDark ? '#000000' : '#f5f5f5', borderBottom: `1px solid ${theme.border}`}}>
              <span style={{ color: 'var(--accent-primary)', fontWeight: 800 }}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={{background:'none', border:'none', color: theme.text, cursor:'pointer'}}><X size={24}/></button>
            </div>
            
            <div style={{...modalBody, background: theme.bg}}>
              <h3 style={{ color: theme.text, marginBottom: '1.5rem' }}>{selectedItem.goal}</h3>
              
              <div className={isDark ? "markdown-dark" : "markdown-light"}>
                <p style={labelSmall}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
                <div style={{...widgetBox, border: `1px solid ${theme.border}`}}>
                   <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>

                <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div style={{...widgetBox, border: `1px solid ${theme.border}`}}>
                   <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-dark p { color: #ffffff !important; line-height: 1.6; }
        .markdown-light p { color: #000000 !important; line-height: 1.6; }
        .reveal-node { animation: fadeIn 0.3s ease; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

/* --- Refined OLED Styles --- */
const containerStyle = { padding: '3rem 1.5rem', maxWidth: '900px', margin: '0 auto', minHeight: '100vh', transition: 'background 0.3s ease' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', paddingBottom: '1rem' };
const vaultBadge = { fontSize: '0.7rem', color: 'var(--accent-primary)', fontWeight: 800, padding: '4px 10px', borderRadius: '5px', border: '1px solid var(--accent-primary)' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1rem' };
const cardStyle = { display: 'flex', padding: '1.5rem', borderRadius: '12px', alignItems: 'center', transition: 'all 0.3s ease' };
const tagRow = { display: 'flex', gap: '15px', marginBottom: '8px' };
const actionColumn = { display: 'flex', gap: '15px', paddingLeft: '1.5rem', marginLeft: '1rem' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer' };

const modalOverlay = { position: 'fixed', inset: 0, backdropFilter: 'blur(10px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999 };
const modalContent = { width: '90%', maxWidth: '750px', borderRadius: '20px', maxHeight: '80vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' };
const modalHeader = { padding: '1rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const modalBody = { padding: '2rem', overflowY: 'auto' };
const widgetBox = { padding: '1.2rem', borderRadius: '10px', marginBottom: '1.5rem' };

const labelSmall = { fontSize: '0.7rem', fontWeight: 900, color: 'var(--accent-primary)', marginBottom: '0.5rem', display: 'flex', alignItems: 'center', gap: '5px' };
const centerStyle = { height: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'monospace' };

export default VaultPage;
